import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../../fixtures/mock-common.js';

const mockReadFileSync = vi.fn();
vi.mock('node:fs', () => ({
  readFileSync: (...args: unknown[]) => mockReadFileSync(...args),
}));

vi.mock('../../../lib/common.js', () => mockCommonBasic());

import { debtMarkerTracker } from '../../../posttool/write/debt-marker-tracker.js';
import { DEBT_TOKEN } from '../../../lib/debt-markers.js';
import type { HookInput } from '../../../types.js';
import { createTestContext } from '../../fixtures/test-context.js';

const T = DEBT_TOKEN;

function makeInput(file = '/proj/src/auth.ts', tool = 'Write'): HookInput {
  return {
    tool_name: tool,
    session_id: 'test',
    tool_input: { file_path: file },
  } as HookInput;
}

describe('debtMarkerTracker', () => {
  let ctx: ReturnType<typeof createTestContext>;

  beforeEach(() => {
    vi.clearAllMocks();
    delete process.env.ORK_DISABLE_DEBT_TRACKER;
    ctx = createTestContext({ projectDir: '/proj' });
    mockReadFileSync.mockReturnValue('const x = 1;');
  });

  it('is silent for non-write tools', () => {
    const r = debtMarkerTracker(makeInput('/proj/src/auth.ts', 'Read'), ctx);
    expect(r.suppressOutput).toBe(true);
  });

  it('is silent for non-code files', () => {
    const r = debtMarkerTracker(makeInput('/proj/notes.md'), ctx);
    expect(r.suppressOutput).toBe(true);
  });

  it('is silent when the file has no markers', () => {
    mockReadFileSync.mockReturnValue('export const y = 2;\n// normal comment');
    const r = debtMarkerTracker(makeInput(), ctx);
    expect(r.suppressOutput).toBe(true);
  });

  it('emits an advisory listing markers found in the written file', () => {
    mockReadFileSync.mockReturnValue(
      [
        'const s = signCookie(uid);',
        `// ${T}: session cookies, upgrade to JWT, when a 2nd service is added`,
      ].join('\n'),
    );
    const r = debtMarkerTracker(makeInput(), ctx);
    const ctxOut = r.hookSpecificOutput?.additionalContext ?? '';
    expect(ctxOut).toContain('debt-marker-tracker');
    expect(ctxOut).toContain('session cookies -> JWT');
    expect(ctxOut).toContain('when a 2nd service is added');
  });

  it('nudges to add a trigger when a marker lacks one', () => {
    mockReadFileSync.mockReturnValue(`// ${T}: skip caching`);
    const r = debtMarkerTracker(makeInput(), ctx);
    expect(r.hookSpecificOutput?.additionalContext).toContain('when <trigger>');
  });

  it('respects the opt-out env var', () => {
    process.env.ORK_DISABLE_DEBT_TRACKER = '1';
    mockReadFileSync.mockReturnValue(`// ${T}: anything, upgrade to better`);
    const r = debtMarkerTracker(makeInput(), ctx);
    expect(r.suppressOutput).toBe(true);
  });

  it('is silent when the file cannot be read', () => {
    mockReadFileSync.mockImplementation(() => { throw new Error('ENOENT'); });
    const r = debtMarkerTracker(makeInput(), ctx);
    expect(r.suppressOutput).toBe(true);
  });
});
